  addSource,
  type KnowledgeBase,
  type KBDocument,
  type KBSource,
  type CreateKnowledgeBaseInput,
  type UpdateKnowledgeBaseInput,
} from '../api/knowledge-bases'

export const useKnowledgeBasesStore = defineStore('knowledgeBases', () => {
  const knowledgeBases = ref<KnowledgeBase[]>([])
